keyframes_css:
@keyframes fall {
  0% {
    transform: translateY(-10px);
    opacity: 1;
  }
  90% {
    opacity: 1;
  }
  100% {
    transform: translateY(200px);
    opacity: 0;
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #2c3e50 0%, #34495e 100%);
  overflow: hidden;
  position: relative;
}

.demo-stage::before,
.demo-stage::after {
  content: '';
  position: absolute;
  width: 2px;
  height: 10px;
  background: #ecf0f1;
  animation: fall 1s infinite linear;
}

.demo-stage::before {
  left: 30px;
  animation-delay: 0s;
}

.demo-stage::after {
  left: 80px;
  animation-delay: 0.3s;
}

.demo-stage .rain1 {
  position: absolute;
  width: 2px;
  height: 10px;
  background: #ecf0f1;
  animation: fall 1.2s infinite linear;
}

.demo-stage .rain1:nth-child(1) {
  left: 50px;
  animation-delay: 0.1s;
}

.demo-stage .rain1:nth-child(2) {
  left: 120px;
  animation-delay: 0.5s;
}

.demo-stage .rain1:nth-child(3) {
  left: 150px;
  animation-delay: 0.8s;
}

@keyframes swing {
  0% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(45deg);
  }
  50% {
    transform: rotate(0deg);
  }
  75% {
    transform: rotate(-45deg);
  }
  100% {
    transform: rotate(0deg);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 10px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.demo-stage .pendulum-container {
  position: relative;
  width: 100px;
  height: 150px;
  display: flex;
  justify-content: center;
}

.demo-stage .pivot {
  position: absolute;
  top: 0;
  width: 12px;
  height: 12px;
  background: #fff;
  border-radius: 50%;
  z-index: 10;
}

.demo-stage .rod {
  position: absolute;
  top: 6px;
  left: 50%;
  width: 4px;
  height: 100px;
  background: #fff;
  transform-origin: top center;
  animation: swing 2s ease-in-out infinite;
}

.demo-stage .bob {
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 20px;
  height: 20px;
  background: #ffd700;
  border-radius: 50%;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

@keyframes settle {
  0% {
    transform: translateY(-200px);
    opacity: 0;
  }
  10% {
    opacity: 1;
  }
  90% {
    opacity: 1;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes shift {
  0%, 100% {
    transform: translateX(0);
  }
  50% {
    transform: translateX(2px);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #87CEEB 0%, #E0F6FF 100%);
  position: relative;
  overflow: hidden;
  border-radius: 4px;
}

.demo-stage .layer {
  position: absolute;
  width: 100%;
  height: 30px;
  animation: settle 3s ease-in forwards, shift 2s ease-in-out infinite;
}

.demo-stage .layer:nth-child(1) {
  background: linear-gradient(90deg, #8B7355 0%, #A0826D 100%);
  animation-delay: 0s, 0s;
  top: 10px;
}

.demo-stage .layer:nth-child(2) {
  background: linear-gradient(90deg, #D2B48C 0%, #DEB887 100%);
  animation-delay: 0.6s, 0.6s;
  top: 40px;
}

.demo-stage .layer:nth-child(3) {
  background: linear-gradient(90deg, #A9A9A9 0%, #C0C0C0 100%);
  animation-delay: 1.2s, 1.2s;
  top: 70px;
}

.demo-stage .layer:nth-child(4) {
  background: linear-gradient(90deg, #CD853F 0%, #DEB887 100%);
  animation-delay: 1.8s, 1.8s;
  top: 100px;
}

.demo-stage .layer:nth-child(5) {
  background: linear-gradient(90deg, #696969 0%, #808080 100%);
  animation-delay: 2.4s, 2.4s;
  top: 130px;
}

.demo-stage .layer:nth-child(6) {
  background: linear-gradient(90deg, #8B4513 0%, #A0522D 100%);
  animation-delay: 3s, 3s;
  top: 160px;
}

@keyframes cicadaWing {
  0%, 100% { transform: scaleX(1) skewY(0deg); opacity: 0.55; }
  50% { transform: scaleX(1.08) skewY(2deg); opacity: 0.75; }
}
@keyframes cicadaBody {
  0%, 100% { transform: translateY(0px) rotate(-2deg); }
  40% { transform: translateY(-3px) rotate(-2deg); }
  70% { transform: translateY(1px) rotate(-2deg); }
}
@keyframes shimmer {
  0%, 100% { opacity: 0.18; transform: translateX(0px) translateY(0px); }
  50% { opacity: 0.38; transform: translateX(4px) translateY(-3px); }
}
@keyframes leafSway {
  0%, 100% { transform: rotate(8deg) translateY(0px); }
  50% { transform: rotate(11deg) translateY(-4px); }
}

.demo-stage {
  width: 200px;
  height: 200px;
  position: relative;
  overflow: hidden;
  background: linear-gradient(160deg, #eceae3 0%, #e4e8dc 60%, #dde6d0 100%);
}

/* 木の幹 */
.demo-stage .trunk {
  position: absolute;
  bottom: 0;
  left: 78px;
  width: 22px;
  height: 160px;
  background: linear-gradient(to right, #c8b89a, #d9c8a8, #bfa880);
  border-radius: 10px 8px 6px 6px;
}
.demo-stage .trunk::before {
  content: '';
  position: absolute;
  left: 3px;
  top: 20px;
  width: 6px;
  height: 80px;
  background: rgba(160,130,90,0.35);
  border-radius: 4px;
}

/* 葉 */
.demo-stage .leaf {
  position: absolute;
  width: 52px;
  height: 28px;
  background: linear-gradient(130deg, #a0c878, #7ab858, #8ec870);
  border-radius: 50% 80% 50% 20%;
  box-shadow: inset 0 2px 4px rgba(100,160,60,0.3);
  animation: leafSway 3.8s ease-in-out infinite;
  transform-origin: left center;
}
.demo-stage .leaf:nth-child(2) {
  top: 32px;
  left: 86px;
  transform: rotate(8deg);
  animation-delay: 0s;
}
.demo-stage .leaf:nth-child(3) {
  top: 54px;
  left: 44px;
  transform: rotate(-140deg) scaleY(0.85);
  animation-delay: 0.6s;
  background: linear-gradient(130deg, #90bc68, #6aaa48);
}
.demo-stage .leaf:nth-child(4) {
  top: 80px;
  left: 94px;
  transform: rotate(20deg) scaleX(0.8);
  animation-delay: 1.1s;
}

/* 蝉 本体 */
.demo-stage .cicada {
  position: absolute;
  top: 78px;
  left: 68px;
  width: 44px;
  height: 26px;
  animation: cicadaBody 2.4s ease-in-out infinite;
}

/* 腹部(胴体) */
.demo-stage .cicada-body {
  position: absolute;
  bottom: 0;
  left: 10px;
  width: 22px;
  height: 22px;
  background: linear-gradient(170deg, #8a7858, #6e6040, #7a6848);
  border-radius: 40% 40% 55% 55%;
  box-shadow: 0 2px 4px rgba(80,60,20,0.25);
}
.demo-stage .cicada-body::before {
  content: '';
  position: absolute;
  top: 3px;
  left: 3px;
  width: 16px;
  height: 8px;
  background: linear-gradient(to bottom, #b8a070, #a08858);
  border-radius: 50%;
  opacity: 0.7;
}
.demo-stage .cicada-body::after {
  content: '';
  position: absolute;
  top: 12px;
  left: 5px;
  width: 12px;
  height: 3px;
  background: repeating-linear-gradient(to right, #6e5830 0px, #6e5830 2px, #907848 2px, #907848 4px);
  border-radius: 2px;
  opacity: 0.8;
}

/* 頭部 */
.demo-stage .cicada-head {
  position: absolute;
  top: 4px;
  left: 12px;
  width: 14px;
  height: 11px;
  background: linear-gradient(160deg, #786448, #5a4c30);
  border-radius: 50% 50% 40% 40%;
  box-shadow: 0 1px 3px rgba(60,40,10,0.3);
}
.demo-stage .cicada-head::before {
  content: '';
  position: absolute;
  top: 3px;
  left: 2px;
  width: 4px;
  height: 4px;
  background: #d0b870;
  border-radius: 50%;
  box-shadow: 6px 0 0 #d0b870;
}

/* 翅(左) */
.demo-stage .wing-left {
  position: absolute;
  top: 0px;
  left: -8px;
  width: 32px;
  height: 20px;
  background: linear-gradient(120deg, rgba(200,220,255,0.62), rgba(180,210,240,0.45));
  border-radius: 70% 30% 60% 20%;
  box-shadow: inset 0 1px 2px rgba(150,180,220,0.4), 0 1px 3px rgba(120,150,200,0.15);
  border: 1px solid rgba(160,190,230,0.45);
  transform-origin: right center;
  animation: cicadaWing 2.4s ease-in-out infinite;
}
.demo-stage .wing-left::before {
  content: '';
  position: absolute;
  top: 3px;
  left: 4px;
  width: 20px;
  height: 9px;
  background: transparent;
  border-radius: 60% 20% 50% 20%;
  border: 1px solid rgba(150,185,230,0.35);
}

/* 翅(右) */
.demo-stage .wing-right {
  position: absolute;
  top: 0px;
  left: 18px;
  width: 32px;
  height: 20px;
  background: linear-gradient(60deg, rgba(200,220,255,0.62), rgba(180,210,240,0.45));
  border-radius: 30% 70% 20% 60%;
  box-shadow: inset 0 1px 2px rgba(150,180,220,0.4), 0 1px 3px rgba(120,150,200,0.15);
  border: 1px solid rgba(160,190,230,0.45);
  transform-origin: left center;
  animation: cicadaWing 2.4s ease-in-out infinite;
  animation-delay: 0.05s;
}
.demo-stage .wing-right::before {
  content: '';
  position: absolute;
  top: 3px;
  left: 6px;
  width: 20px;
  height: 9px;
  background: transparent;
  border-radius: 20% 60% 20% 50%;
  border: 1px solid rgba(150,185,230,0.35);
}

/* 光の粒 */
.demo-stage .shimmer {
  position: absolute;
  border-radius: 50%;
  background: rgba(255,240,180,0.55);
  animation: shimmer 3s ease-in-out infinite;
}
.demo-stage .shimmer:nth-of-type(1) {
  width: 7px; height: 7px;
  top: 22px; left: 138px;
  animation-delay: 0s;
}
.demo-stage .shimmer:nth-of-type(2) {
  width: 4px; height: 4px;
  top: 140px; left: 40px;
  animation-delay: 1.2s;
}
.demo-stage .shimmer:nth-of-type(3) {
  width: 5px; height: 5px;
  top: 168px; left: 155px;
  animation-delay: 2s;
}

@keyframes waveSwell {
  0%   { transform: translateX(0) scaleY(1); }
  50%  { transform: translateX(-18px) scaleY(1.18); }
  100% { transform: translateX(0) scaleY(1); }
}
@keyframes waveShift {
  0%   { transform: translateX(0) scaleY(1); }
  50%  { transform: translateX(22px) scaleY(0.88); }
  100% { transform: translateX(0) scaleY(1); }
}
@keyframes foamFloat {
  0%   { transform: translateY(0) scale(1); opacity: 0.7; }
  50%  { transform: translateY(-6px) scale(1.12); opacity: 1; }
  100% { transform: translateY(0) scale(1); opacity: 0.7; }
}
@keyframes sunGlow {
  0%   { box-shadow: 0 0 10px 4px #f0d898, 0 0 0 0 #e8c870; }
  50%  { box-shadow: 0 0 18px 8px #f0d898, 0 0 28px 10px #e8c87044; }
  100% { box-shadow: 0 0 10px 4px #f0d898, 0 0 0 0 #e8c870; }
}

.demo-stage {
  width: 200px;
  height: 200px;
  position: relative;
  overflow: hidden;
  background: linear-gradient(180deg, #d4e8f4 0%, #b8d8ee 45%, #a8cce4 100%);
}

/* 太陽 */
.demo-stage .sun {
  position: absolute;
  top: 18px;
  left: 50%;
  transform: translateX(-50%);
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: radial-gradient(circle, #f8e888 60%, #e8c870 100%);
  box-shadow: 0 0 10px 4px #f0d898;
  animation: sunGlow 4s ease-in-out infinite;
}

/* 遠景の小さな波 */
.demo-stage .wave-far {
  position: absolute;
  bottom: 82px;
  left: -20px;
  width: 240px;
  height: 28px;
  border-radius: 50% 50% 0 0 / 100% 100% 0 0;
  background: linear-gradient(180deg, #90b8d8 0%, #78a8cc 100%);
  opacity: 0.6;
  animation: waveShift 5s ease-in-out infinite;
}

/* 中景の波 */
.demo-stage .wave-mid {
  position: absolute;
  bottom: 62px;
  left: -30px;
  width: 260px;
  height: 40px;
  border-radius: 50% 50% 0 0 / 100% 100% 0 0;
  background: linear-gradient(180deg, #78b0d0 0%, #60a0c4 100%);
  opacity: 0.8;
  animation: waveSwell 4s ease-in-out infinite;
}
.demo-stage .wave-mid::before {
  content: '';
  position: absolute;
  top: -10px;
  left: 60px;
  width: 80px;
  height: 20px;
  border-radius: 50%;
  background: rgba(255,255,255,0.28);
}

/* 主役の波 */
.demo-stage .wave-main {
  position: absolute;
  bottom: 36px;
  left: -40px;
  width: 280px;
  height: 64px;
  border-radius: 50% 50% 0 0 / 100% 100% 0 0;
  background: linear-gradient(180deg, #5898c0 0%, #4888b4 60%, #3878a8 100%);
  animation: waveSwell 3.5s ease-in-out infinite;
}
.demo-stage .wave-main::before {
  content: '';
  position: absolute;
  top: -14px;
  left: 30px;
  width: 120px;
  height: 28px;
  border-radius: 50% 60% 40% 50% / 60% 50% 50% 40%;
  background: rgba(255,255,255,0.35);
  animation: foamFloat 3.5s ease-in-out infinite;
}
.demo-stage .wave-main::after {
  content: '';
  position: absolute;
  top: -8px;
  right: 40px;
  width: 60px;
  height: 16px;
  border-radius: 50%;
  background: rgba(255,255,255,0.22);
  animation: foamFloat 3.5s ease-in-out infinite 0.6s;
}

/* 前景の波（海底） */
.demo-stage .wave-front {
  position: absolute;
  bottom: 0;
  left: -20px;
  width: 240px;
  height: 50px;
  border-radius: 50% 50% 0 0 / 100% 100% 0 0;
  background: linear-gradient(180deg, #3878a8 0%, #2d6898 100%);
  animation: waveShift 3s ease-in-out infinite;
}

/* 泡1 */
.demo-stage .foam-1 {
  position: absolute;
  bottom: 48px;
  left: 30px;
  width: 12px;
  height: 8px;
  border-radius: 50%;
  background: rgba(255,255,255,0.55);
  animation: foamFloat 2.5s ease-in-out infinite 0.3s;
}
/* 泡2 */
.demo-stage .foam-2 {
  position: absolute;
  bottom: 52px;
  left: 70px;
  width: 8px;
  height: 6px;
  border-radius: 50%;
  background: rgba(255,255,255,0.45);
  animation: foamFloat 3s ease-in-out infinite 1s;
}
/* 泡3 */
.demo-stage .foam-3 {
  position: absolute;
  bottom: 46px;
  left: 140px;
  width: 10px;
  height: 7px;
  border-radius: 50%;
  background: rgba(255,255,255,0.5);
  animation: foamFloat 2.8s ease-in-out infinite 0.7s;
}

@keyframes flameMain {
  0%   { transform: scaleX(1)   scaleY(1)   translateY(0px);  border-radius: 50% 50% 30% 30% / 60% 60% 40% 40%; }
  25%  { transform: scaleX(0.88) scaleY(1.06) translateY(-3px); border-radius: 55% 45% 28% 32% / 62% 58% 42% 38%; }
  50%  { transform: scaleX(1.08) scaleY(0.97) translateY(2px);  border-radius: 45% 55% 32% 28% / 58% 62% 38% 42%; }
  75%  { transform: scaleX(0.93) scaleY(1.04) translateY(-2px); border-radius: 52% 48% 30% 30% / 60% 60% 40% 40%; }
  100% { transform: scaleX(1)   scaleY(1)   translateY(0px);  border-radius: 50% 50% 30% 30% / 60% 60% 40% 40%; }
}

@keyframes flameMid {
  0%   { transform: scaleX(1)   scaleY(1)   translateY(0px) rotate(-1deg); }
  33%  { transform: scaleX(0.85) scaleY(1.08) translateY(-4px) rotate(2deg); }
  66%  { transform: scaleX(1.1)  scaleY(0.95) translateY(2px)  rotate(-2deg); }
  100% { transform: scaleX(1)   scaleY(1)   translateY(0px) rotate(-1deg); }
}

@keyframes flameTip {
  0%   { transform: scaleX(1)   scaleY(1)   translateY(0px) rotate(0deg);  opacity: 0.85; }
  30%  { transform: scaleX(0.78) scaleY(1.12) translateY(-6px) rotate(3deg);  opacity: 1; }
  60%  { transform: scaleX(1.15) scaleY(0.92) translateY(3px)  rotate(-3deg); opacity: 0.75; }
  100% { transform: scaleX(1)   scaleY(1)   translateY(0px) rotate(0deg);  opacity: 0.85; }
}

@keyframes emberFloat {
  0%   { transform: translate(0px, 0px) scale(1);   opacity: 0.9; }
  50%  { transform: translate(4px, -18px) scale(0.7); opacity: 0.6; }
  100% { transform: translate(-2px, -36px) scale(0.3); opacity: 0; }
}

@keyframes glowPulse {
  0%   { opacity: 0.35; transform: scale(1); }
  50%  { opacity: 0.55; transform: scale(1.06); }
  100% { opacity: 0.35; transform: scale(1); }
}

@keyframes logRock {
  0%   { transform: rotate(-1deg); }
  50%  { transform: rotate(1deg); }
  100% { transform: rotate(-1deg); }
}

.demo-stage {
  width: 200px;
  height: 200px;
  position: relative;
  overflow: hidden;
  background: linear-gradient(170deg, #ececea 0%, #e4e2de 60%, #dedad4 100%);
}

/* 地面 */
.demo-stage .ground {
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 38px;
  background: linear-gradient(180deg, #cec8be 0%, #bfb9ae 100%);
  border-radius: 0;
}

/* 薪 左 */
.demo-stage .log-left {
  position: absolute;
  bottom: 26px;
  left: 58px;
  width: 56px;
  height: 14px;
  background: linear-gradient(180deg, #b09070 0%, #8a6a50 100%);
  border-radius: 7px;
  transform: rotate(-18deg);
  box-shadow: 0 2px 4px rgba(100,70,40,0.3);
  animation: logRock 5s ease-in-out infinite;
}

/* 薪 右 */
.demo-stage .log-right {
  position: absolute;
  bottom: 26px;
  left: 90px;
  width: 56px;
  height: 14px;
  background: linear-gradient(180deg, #b09070 0%, #8a6a50 100%);
  border-radius: 7px;
  transform: rotate(18deg);
  box-shadow: 0 2px 4px rgba(100,70,40,0.3);
  animation: logRock 5s ease-in-out infinite reverse;
}

/* 炎 底部（もっとも明るいオレンジ） */
.demo-stage .flame-base {
  position: absolute;
  bottom: 34px;
  left: 50%;
  transform: translateX(-50%);
  width: 72px;
  height: 72px;
  background: radial-gradient(ellipse at 50% 80%, #f0c070 0%, #e8903a 55%, #d06020 100%);
  border-radius: 50% 50% 30% 30% / 60% 60% 40% 40%;
  box-shadow: 0 0 18px 6px rgba(230,140,50,0.45);
  animation: flameMain 2.4s cubic-bezier(0.45, 0.05, 0.55, 0.95) infinite;
}

/* 炎 中段（やや赤みを帯びた橙） */
.demo-stage .flame-mid {
  position: absolute;
  bottom: 62px;
  left: 50%;
  transform: translateX(-50%);
  width: 50px;
  height: 62px;
  background: radial-gradient(ellipse at 50% 75%, #f0a850 0%, #d86030 60%, #c04020 100%);
  border-radius: 50% 50% 30% 30% / 65% 65% 35% 35%;
  box-shadow: 0 0 12px 4px rgba(210,100,40,0.35);
  animation: flameMid 1.9s cubic-bezier(0.4, 0.0, 0.6, 1.0) infinite;
  animation-delay: -0.3s;
}

/* 炎 先端（赤みが強い） */
.demo-stage .flame-tip {
  position: absolute;
  bottom: 108px;
  left: 50%;
  transform: translateX(-50%);
  width: 28px;
  height: 46px;
  background: radial-gradient(ellipse at 50% 70%, #e88050 0%, #c84030 55%, #a02820 100%);
  border-radius: 50% 50% 30% 30% / 70% 70% 30% 30%;
  opacity: 0.85;
  animation: flameTip 1.5s cubic-bezier(0.3, 0.0, 0.7, 1.0) infinite;
  animation-delay: -0.6s;
}

/* 炎 先端の光芒 */
.demo-stage .flame-tip::after {
  content: '';
  position: absolute;
  top: 4px;
  left: 50%;
  transform: translateX(-50%);
  width: 10px;
  height: 20px;
  background: radial-gradient(ellipse at 50% 60%, #f8d090 0%, transparent 80%);
  border-radius: 50%;
  opacity: 0.7;
}

/* 光のにじみ（グロー） */
.demo-stage .glow {
  position: absolute;
  bottom: 20px;
  left: 50%;
  transform: translateX(-50%);
  width: 110px;
  height: 80px;
  background: radial-gradient(ellipse at 50% 70%, rgba(240,170,60,0.55) 0%, rgba(220,120,40,0.2) 55%, transparent 80%);
  border-radius: 50%;
  animation: glowPulse 2.4s ease-in-out infinite;
}

/* 火の粉 1 */
.demo-stage .ember-1 {
  position: absolute;
  bottom: 100px;
  left: 96px;
  width: 5px;
  height: 5px;
  background: #f0b040;
